import{_ as t,o,c as r,ag as a}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"File recovery mode in Aerosol","description":"Read-only folder scans, signature-based hits, media previews, and copy-out recovery — how it works and what it is not (yet).","frontmatter":{"title":"File recovery mode in Aerosol","description":"Read-only folder scans, signature-based hits, media previews, and copy-out recovery — how it works and what it is not (yet).","date":"2026-04-07T00:00:00.000Z"},"headers":[],"relativePath":"blog/file-recovery-mode.md","filePath":"blog/file-recovery-mode.md","lastUpdated":1775592403000}'),s={name:"blog/file-recovery-mode.md"};function i(n,e,l,d,c,h){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="file-recovery-mode-in-aerosol" tabindex="-1">File recovery mode in Aerosol <a class="header-anchor" href="#file-recovery-mode-in-aerosol" aria-label="Permalink to &quot;File recovery mode in Aerosol&quot;">​</a></h1><p>Aerosol started as a <strong>cleanup</strong> tool: find reclaimable clutter, label risk, preview deletes. We’ve added a second mode, <strong>File recovery</strong>, for a different job: <strong>locate files</strong> under a path you choose, <strong>inspect</strong> them (including <strong>image and video previews</strong>), and <strong>copy</strong> selections into another folder — <strong>without modifying the source</strong>.</p><p>You switch modes from the app header (<strong>Cleanup</strong> | <strong>File recovery</strong>). Recovery uses its own Rust engine (<a href="https://github.com/januscaler/aerosol/tree/main/crates/aerosol_recovery" target="_blank" rel="noreferrer"><code>aerosol_recovery</code></a>) behind the same Tauri shell.</p><h2 id="what-it-does-today" tabindex="-1">What it does today <a class="header-anchor" href="#what-it-does-today" aria-label="Permalink to &quot;What it does today&quot;">​</a></h2><ul><li><strong>Source</strong> — Pick a folder with the system picker, type a path, or use volume shortcuts. The scanner walks that <strong>directory tree</strong> read-only.</li><li><strong>Quick vs Deep</strong> — <em>Quick</em> matches magic bytes and extensions. <em>Deep</em> also looks for known signatures in an early slice of each file (useful for embedded or misnamed data); it is slower.</li><li><strong>Types</strong> — Built-in filters include PNG, JPEG, ZIP, PDF, MP4, SQLite, and JSON (leave all unchecked to include every built-in signature).</li><li><strong>Results</strong> — Paginated list with categories; <strong>Preview</strong> on rows that are real image/video <strong>files</strong> (not “carved” offsets inside a container).</li><li><strong>Recover</strong> — Copies selected hits to an output folder you choose. Settings can remember that folder for the next dialog.</li><li><strong>Safety</strong> — Recovery does not write to the scan source; output always goes elsewhere. SSDs with TRIM and deleted data are still a limitation for any recovery story — we surface that in the UI.</li></ul><h2 id="what-it-is-not-yet" tabindex="-1">What it is not (yet) <a class="header-anchor" href="#what-it-is-not-yet" aria-label="Permalink to &quot;What it is not (yet)&quot;">​</a></h2><p>This is <strong>not</strong> a full forensic or raw-partition undelete product: there is <strong>no</strong> NTFS MFT / ext4 inode / APFS catalog parser in the shipping path yet. <strong>Carved</strong> hits may appear in results but are <strong>not</strong> extracted as separate files in the current build.</p><p>Defaults and caps (e.g. max files per scan) live under <strong>Settings → File recovery</strong>.</p><h2 id="try-it" tabindex="-1">Try it <a class="header-anchor" href="#try-it" aria-label="Permalink to &quot;Try it&quot;">​</a></h2><p>Binaries: <a href="/#download">home page</a> or <a href="https://github.com/januscaler/aerosol/releases" target="_blank" rel="noreferrer">GitHub Releases</a>. For step-by-step use, see the <a href="/manual#file-recovery">user manual → File recovery</a>.</p>',10)])])}const p=t(s,[["render",i]]);export{u as __pageData,p as default};
